 3→import java.util.List;
 4→
 5→public enum TaskStatus {
 6→    TODO {
 7→        @Override
 8→        public List<TaskStatus> getAllowedTransitions() {
 9→            return List.of(IN_PROGRESS);
10→        }
11→    },
12→    IN_PROGRESS {
13→        @Override
14→        public List<TaskStatus> getAllowedTransitions() {
15→            return List.of(TODO, DONE);
16→        }
17→    },
18→    DONE {
19→        @Override
20→        public List<TaskStatus> getAllowedTransitions() {
21→            return List.of(CLOSED);
22→        }
23→    },
24→    CLOSED {
25→        @Override
26→        public List<TaskStatus> getAllowedTransitions() {
27→            return List.of();
28→        }
29→    };
30→
31→    public abstract List<TaskStatus> getAllowedTransitions();
32→
33→    public boolean canTransitionTo(TaskStatus target) {
34→        return target != null && getAllowedTransitions().contains(target);
35→    }
36→}
