 1→package com.taskflow.service;
 2→
 3→import com.taskflow.dto.CreateTaskRequest;
 4→import com.taskflow.dto.UpdateTaskRequest;
 5→import com.taskflow.entity.Task;
 6→import com.taskflow.exception.ResourceNotFoundException;
 7→import com.taskflow.repository.TaskRepository;
 8→import org.springframework.data.domain.Page;
 9→import org.springframework.data.domain.PageRequest;
10→import org.springframework.data.domain.Pageable;
11→import org.springframework.data.domain.Sort;
12→import org.springframework.stereotype.Service;
13→import org.springframework.transaction.annotation.Transactional;
14→
15→@Service
16→public class TaskService {
17→
18→    private final TaskRepository taskRepository;
19→
20→    public TaskService(TaskRepository taskRepository) {
21→        this.taskRepository = taskRepository;
22→    }
23→
24→    @Transactional
25→    public Task create(CreateTaskRequest request, Long userId) {
26→        Task task = new Task();
27→        task.setTitle(request.getTitle());
28→        task.setDescription(request.getDescription());
29→        task.setPriority(request.getPriority());
30→        task.setCreatedBy(userId);
31→        return taskRepository.save(task);
32→    }
33→
34→    @Transactional(readOnly = true)
35→    public Task getById(Long id) {
36→        Task task = taskRepository.findById(id)
37→                .orElseThrow(() -> new ResourceNotFoundException("Task not found with id: " + id));
38→        if (task.isDeleted()) {
39→            throw new ResourceNotFoundException("Task not found with id: " + id);
40→        }
41→        return task;
42→    }
43→
44→    @Transactional
45→    public Task update(Long id, UpdateTaskRequest request) {
46→        Task task = getById(id);
47→        task.setTitle(request.getTitle());
48→        task.setDescription(request.getDescription());
49→        if (request.getPriority() != null) {
50→            task.setPriority(request.getPriority());
51→        }
52→        return taskRepository.save(task);
53→    }
54→
55→    @Transactional
56→    public void softDelete(Long id) {
57→        Task task = getById(id);
58→        task.setDeleted(true);
59→        taskRepository.save(task);
60→    }
61→
62→    @Transactional(readOnly = true)
63→    public Page<Task> list(String keyword, Task.Priority priority, int page, int size) {
64→        Pageable pageable = PageRequest.of(page, size, Sort.by(Sort.Direction.DESC, "createdAt"));
65→
66→        if (keyword != null && !keyword.isBlank() && priority != null) {
67→            return taskRepository.findByDeletedFalseAndTitleContainingIgnoreCaseAndPriority(keyword, priority, pageable);
68→        } else if (keyword != null && !keyword.isBlank()) {
69→            return taskRepository.findByDeletedFalseAndTitleContainingIgnoreCase(keyword, pageable);
70→        } else if (priority != null) {
71→            return taskRepository.findByDeletedFalseAndPriority(priority, pageable);
72→        } else {
73→            return taskRepository.findByDeletedFalse(pageable);
74→        }
75→    }
76→}
