 1→package com.taskflow.controller;
 2→
 3→import com.taskflow.dto.CreateTaskRequest;
 4→import com.taskflow.dto.PageResponse;
 5→import com.taskflow.dto.TaskResponse;
 6→import com.taskflow.dto.UpdateTaskRequest;
 7→import com.taskflow.entity.Task;
 8→import com.taskflow.service.TaskService;
 9→import jakarta.validation.Valid;
10→import org.springframework.data.domain.Page;
11→import org.springframework.http.HttpStatus;
12→import org.springframework.http.ResponseEntity;
13→import org.springframework.security.core.Authentication;
14→import org.springframework.web.bind.annotation.*;
15→
16→import java.util.List;
17→
18→@RestController
19→@RequestMapping("/api/tasks")
20→public class TaskController {
21→
22→    private final TaskService taskService;
23→
24→    public TaskController(TaskService taskService) {
25→        this.taskService = taskService;
26→    }
27→
28→    @PostMapping
29→    public ResponseEntity<TaskResponse> createTask(@Valid @RequestBody CreateTaskRequest request,
30→                                                   Authentication authentication) {
31→        Long userId = (Long) authentication.getPrincipal();
32→        Task task = taskService.create(request, userId);
33→        return ResponseEntity.status(HttpStatus.CREATED).body(toResponse(task));
34→    }
35→
36→    @GetMapping("/{id}")
37→    public ResponseEntity<TaskResponse> getTask(@PathVariable Long id) {
38→        Task task = taskService.getById(id);
39→        return ResponseEntity.ok(toResponse(task));
40→    }
41→
42→    @PutMapping("/{id}")
43→    public ResponseEntity<TaskResponse> updateTask(@PathVariable Long id,
44→                                                   @Valid @RequestBody UpdateTaskRequest request) {
45→        Task task = taskService.update(id, request);
46→        return ResponseEntity.ok(toResponse(task));
47→    }
48→
49→    @DeleteMapping("/{id}")
50→    public ResponseEntity<Void> deleteTask(@PathVariable Long id) {
51→        taskService.softDelete(id);
52→        return ResponseEntity.noContent().build();
53→    }
54→
55→    @GetMapping
56→    public ResponseEntity<PageResponse<TaskResponse>> listTasks(
57→            @RequestParam(required = false) String keyword,
58→            @RequestParam(required = false) String priority,
59→            @RequestParam(defaultValue = "0") int page,
60→            @RequestParam(defaultValue = "20") int size) {
61→
62→        Task.Priority priorityEnum = null;
63→        if (priority != null && !priority.isBlank()) {
64→            priorityEnum = Task.Priority.valueOf(priority);
65→        }
66→
67→        Page<Task> taskPage = taskService.list(keyword, priorityEnum, page, size);
68→
69→        List<TaskResponse> content = taskPage.getContent().stream()
70→                .map(this::toResponse)
71→                .toList();
72→
73→        PageResponse<TaskResponse> response = new PageResponse<>();
74→        response.setContent(content);
75→        response.setPage(taskPage.getNumber());
76→        response.setSize(taskPage.getSize());
77→        response.setTotalElements(taskPage.getTotalElements());
78→        response.setTotalPages(taskPage.getTotalPages());
79→
80→        return ResponseEntity.ok(response);
81→    }
82→
83→    private TaskResponse toResponse(Task task) {
84→        TaskResponse response = new TaskResponse();
85→        response.setId(task.getId());
86→        response.setTitle(task.getTitle());
87→        response.setDescription(task.getDescription());
88→        response.setPriority(task.getPriority());
89→        response.setStatus(task.getStatus());
90→        response.setCreatedBy(task.getCreatedBy());
91→        response.setCreatedAt(task.getCreatedAt());
92→        response.setUpdatedAt(task.getUpdatedAt());
93→        return response;
94→    }
95→}
