 1→package com.taskflow.exception;
 2→
 3→import org.springframework.http.HttpStatus;
 4→import org.springframework.http.ResponseEntity;
 5→import org.springframework.web.bind.MethodArgumentNotValidException;
 6→import org.springframework.web.bind.annotation.ExceptionHandler;
 7→import org.springframework.web.bind.annotation.RestControllerAdvice;
 8→
 9→import java.util.HashMap;
10→import java.util.List;
11→import java.util.Map;
12→
13→@RestControllerAdvice
14→public class GlobalExceptionHandler {
15→
16→    @ExceptionHandler(MethodArgumentNotValidException.class)
17→    public ResponseEntity<Map<String, Object>> handleValidationException(MethodArgumentNotValidException ex) {
18→        Map<String, Object> body = new HashMap<>();
19→        body.put("status", 400);
20→        body.put("message", "Validation failed");
21→
22→        List<String> errors = ex.getBindingResult().getFieldErrors().stream()
23→                .map(fe -> fe.getField() + ": " + fe.getDefaultMessage())
24→                .toList();
25→        body.put("errors", errors);
26→
27→        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(body);
28→    }
29→
30→    @ExceptionHandler(ResourceNotFoundException.class)
31→    public ResponseEntity<Map<String, Object>> handleNotFound(ResourceNotFoundException ex) {
32→        Map<String, Object> body = new HashMap<>();
33→        body.put("status", 404);
34→        body.put("message", ex.getMessage());
35→        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(body);
36→    }
37→
38→    @ExceptionHandler(DuplicateException.class)
39→    public ResponseEntity<Map<String, Object>> handleDuplicate(DuplicateException ex) {
40→        Map<String, Object> body = new HashMap<>();
41→        body.put("status", 409);
42→        body.put("message", ex.getMessage());
43→        return ResponseEntity.status(HttpStatus.CONFLICT).body(body);
44→    }
45→}
