 1→package com.taskflow.config;
 2→
 3→import com.taskflow.security.JwtAuthFilter;
 4→import org.springframework.context.annotation.Bean;
 5→import org.springframework.context.annotation.Configuration;
 6→import org.springframework.security.config.annotation.web.builders.HttpSecurity;
 7→import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
 8→import org.springframework.security.config.http.SessionCreationPolicy;
 9→import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
10→import org.springframework.security.crypto.password.PasswordEncoder;
11→import org.springframework.security.web.SecurityFilterChain;
12→import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
13→import jakarta.servlet.http.HttpServletResponse;
14→
15→@Configuration
16→@EnableWebSecurity
17→public class SecurityConfig {
18→
19→    private final JwtAuthFilter jwtAuthFilter;
20→
21→    public SecurityConfig(JwtAuthFilter jwtAuthFilter) {
22→        this.jwtAuthFilter = jwtAuthFilter;
23→    }
24→
25→    @Bean
26→    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
27→        http
28→            .csrf(csrf -> csrf.disable())
29→            .sessionManagement(session ->
30→                session.sessionCreationPolicy(SessionCreationPolicy.STATELESS)
31→            )
32→            .authorizeHttpRequests(auth -> auth
33→                .requestMatchers("/api/auth/**").permitAll()
34→                .requestMatchers("/h2-console/**").permitAll()
35→                .anyRequest().authenticated()
36→            )
37→            .exceptionHandling(ex -> ex
38→                .authenticationEntryPoint((request, response, authException) ->
39→                    response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Unauthorized"))
40→            )
41→            .headers(headers ->
42→                headers.frameOptions(frameOptions -> frameOptions.sameOrigin())
43→            )
44→            .addFilterBefore(jwtAuthFilter, UsernamePasswordAuthenticationFilter.class);
45→
46→        return http.build();
47→    }
48→
49→    @Bean
50→    public PasswordEncoder passwordEncoder() {
51→        return new BCryptPasswordEncoder();
52→    }
53→}
