    // ── Additional: Full lifecycle chain ─────────────────────────────────

    @Nested
    @DisplayName("Additional: Full lifecycle transition chain")
    class FullLifecycle {

        @Test
        @DisplayName("Full chain TODO -> IN_PROGRESS -> DONE -> CLOSED succeeds")
        void shouldCompleteFullLifecycleChain() throws Exception {
            JsonNode created = createTaskViaApi("Full Lifecycle Task");
            long taskId = created.get("id").asLong();
            assertThat(created.get("status").asText()).isEqualTo("TODO");

            JsonNode step1 = transitionStatusExpect200(taskId, "IN_PROGRESS");
            assertThat(step1.get("status").asText()).isEqualTo("IN_PROGRESS");

            JsonNode step2 = transitionStatusExpect200(taskId, "DONE");
            assertThat(step2.get("status").asText()).isEqualTo("DONE");

            JsonNode step3 = transitionStatusExpect200(taskId, "CLOSED");
            assertThat(step3.get("status").asText()).isEqualTo("CLOSED");
        }

        @Test
        @DisplayName("Transition does not change other task fields (title, description, priority)")
        void transitionShouldNotChangeOtherFields() throws Exception {
            JsonNode created = createTaskViaApi("Unchanged Title");
            long taskId = created.get("id").asLong();
            String originalTitle = created.get("title").asText();
            String originalDescription = created.get("description").asText();
            String originalPriority = created.get("priority").asText();

            JsonNode afterTransition = transitionStatusExpect200(taskId, "IN_PROGRESS");

            assertThat(afterTransition.get("title").asText()).isEqualTo(originalTitle);
            assertThat(afterTransition.get("description").asText()).isEqualTo(originalDescription);
            assertThat(afterTransition.get("priority").asText()).isEqualTo(originalPriority);
            assertThat(afterTransition.get("createdBy").asLong()).isEqualTo(testUserId);
        }
    }

